import React, { useState } from 'react';
import { View, Button, Alert } from 'react-native';
import { RNIap, purchaseErrorListener, purchaseUpdatedListener } from 'react-native-iap';

const itemSkus = ['your_product_id']; // Replace with your product IDs

const PaymentModule = () => {
  const [isLoading, setIsLoading] = useState(false);

  const initIAP = async () => {
    try {
      await RNIap.initConnection();
      const products = await RNIap.getProducts(itemSkus);
      console.log('Products:', products);
    } catch (err) {
      console.warn(err);
    }
  };

  const requestPurchase = async (sku) => {
    try {
      setIsLoading(true);
      await RNIap.requestPurchase(sku);
    } catch (err) {
      Alert.alert('Purchase Error', err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const purchaseUpdateSubscription = purchaseUpdatedListener((purchase) => {
    const receipt = purchase.transactionReceipt;
    if (receipt) {
      // Validate receipt with your server
      // Handle successful purchase
      Alert.alert('Purchase Successful', 'Thank you for your purchase!');
    }
  });

  const purchaseErrorSubscription = purchaseErrorListener((error) => {
    Alert.alert('Purchase Error', error.message);
  });

  React.useEffect(() => {
    initIAP();
    return () => {
      purchaseUpdateSubscription.remove();
      purchaseErrorSubscription.remove();
      RNIap.endConnection();
    };
  }, []);

  return (
    <View>
      <Button
        title={isLoading ? 'Processing...' : 'Buy Product'}
        onPress={() => requestPurchase(itemSkus[0])}
        disabled={isLoading}
      />
    </View>
  );
};

export default PaymentModule;